parameters.jsCode:
// 1. Grab the stringified JSON from the 'output' field
const rawJsonString = $input.first().json.output;

// 2. Parse the string back into a real data array
const parsedArray = JSON.parse(rawJsonString);

// 3. Map it into n8n's standard item format so it runs the next node 5 times
return parsedArray.map(item => ({ json: item }));

// Read all accumulated URLs collected across every loop iteration
const staticData = $getWorkflowStaticData('global');
const imageUrls = staticData.collectedUrls || [];

// Reset for the next workflow run
staticData.collectedUrls = [];

// Use the caption from the first generated slide
const postCaption = $('Parse_Array').first().json.caption;

return [{
  json: {
    image_urls: imageUrls,
    caption: postCaption
  }
}];

// Accumulate this iteration's uploaded URL into persistent workflow memory
const staticData = $getWorkflowStaticData('global');
if (!staticData.collectedUrls) staticData.collectedUrls = [];

const uploadedItems = $('Upload a File').all();
for (const item of uploadedItems) {
  if (item?.json?.url) {
    staticData.collectedUrls.push(item.json.url);
  }
}

// Original 15-second pause to respect Instagram rate limits
await new Promise(resolve => setTimeout(resolve, 15000));

return $input.all();
